:root {
  --card-bg: #ffffff;
  --card-border: #e8e0f0;
  --accent: #7c4dbd;
  --accent-light: #f0eafa;
  --accent-mid: #c4a8e8;
  --text-primary: #1e1530;
  --text-secondary: #6b5f7a;
  --text-muted: #a89bbf;
  --bar-filled: #7c4dbd;
  --bar-empty: #e8e0f0;
  --tag-bg: #f0eafa;
  --tag-text: #7c4dbd;
  --cuisine-bg: #7c4dbd;
  --cuisine-text: #ffffff;
  --time-bg: #f0eafa;
  --time-text: #7c4dbd;
  --divider: #e8e0f0;
  --stat-value-color: #1e1530;
  --stat-label-color: #a89bbf;
  --difficulty-text-color: #7c4dbd;
}

.card {
  background: var(--card-bg);
  border: 2px solid var(--card-border);
  border-radius: 16px;
  padding: 20px;
  width: 420px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.cuisine-tag {
  background: var(--cuisine-bg);
  color: var(--cuisine-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 20px;
}

.time-badge {
  background: var(--time-bg);
  color: var(--time-text);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}

.recipe-title {
  font-size: 22px;
  font-weight: 800;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.2;
}

.recipe-desc {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.5;
  margin: 0;
}

.difficulty-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.difficulty-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.difficulty-bars {
  display: flex;
  gap: 4px;
  align-items: center;
}

.bar {
  width: 28px;
  height: 8px;
  border-radius: 4px;
}

.bar--filled {
  background: var(--bar-filled);
}

.bar--empty {
  background: var(--bar-empty);
}

.difficulty-text {
  font-size: 12px;
  font-weight: 700;
  color: var(--difficulty-text-color);
}

.stats-row {
  display: flex;
  align-items: center;
  background: var(--accent-light);
  border-radius: 12px;
  padding: 12px 0;
}

.stat {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 20px;
  font-weight: 800;
  color: var(--stat-value-color);
  line-height: 1;
}

.stat-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--stat-label-color);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.stat-divider {
  width: 1px;
  height: 32px;
  background: var(--divider);
}

.tag-row {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 12px;
  font-weight: 600;
  padding: 5px 12px;
  border-radius: 20px;
  border: 1px solid var(--accent-mid);
}
